| part_of = {{ill|Kayo Kofun Cluster|ja|萱生古墳群|lt=Kayō Kofun Group|1=Ōyamato Kofun Group|qq=draft}} ({{ill|Yamato Kofun Cluster|ja|大和古墳群|1=Ōyamato Kofun Group|qq=draft}})
| location = Nakayama Town, Tenri City, Nara Prefecture
| coordinates = {{coordinates|34|33|57|N|135|50|53|E|map_size:10000}}
| type = Keyhole-shaped tumulus
| area = Total length: 130m
| burial = {{ill|Vertical stone chamber|ja|竪穴式石室|1=Vertical Pit-Style Stone Chamber|2=ja|3=竪穴式石室|4=zh|5=豎穴式石室|1=Vertical Pit-Style Stone Chamber|qq=draft}}, split-bamboo-shaped wooden coffin
| built = Late 3rd century<ref name=tenri>{{Cite web|url=https://www.city.tenri.nara.jp/kakuka/kyouikuiinkai/bunkazaika/kohun/1403514037345.html|title=Nakayama Otsuka Kofun|publisher=Tenri City|accessdate=2021}}</ref>
| Interred_individual = Unknown<br />Traditionally attributed to {{ill|Nunakakura no Hime no Mikoto|ja|渟名城入姫命|qq=draft}}
| Excavated_items = Fragments of mirrors, iron swords, and arrowheads<br />{{ill|Miyama-style special pedestal and jar|ja|特殊器台・特殊壺|1=Special platforms and jars|1=Special platforms and jars|lt=Special plattypes and jars|qq=draft}}<br />{{ill|Cylindrical haniwa|ja|円筒埴輪|1=Cylindrical Haniwa|qq=draft}}
| designation1 = National Historic Site (as part of {{ill|Yamato Kofun Cluster|ja|大和古墳群|1=Ōyamato Kofun Group|qq=draft}})
