| location = Nakayama Town, Tenri City, Nara Prefecture
| coordinates = {{coordinates|34|33|57|N|135|50|53|E|map_size:10000}}
| type = Keyhole-shaped tumulus
| area = Total length: 130m
| burial = {{ill|Vertical stone chamber|ja|竪穴式石室|1=Vertical Pit-Style Stone Chamber|2=ja|3=竪穴式石室|4=zh|5=豎穴式石室|1=Vertical Pit-Style Stone Chamber|qq=draft}}, split-bamboo-shaped wooden coffin
| built = Late 3rd century<ref name=tenri>{{Cite web|url=https://www.city.tenri.nara.jp/kakuka/kyouikuiinkai/bunkazaika/kohun/1403514037345.html|title=Nakayama Otsuka Kofun|publisher=Tenri City|accessdate=2021}}</ref>
